import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        a = [int(next(it)) for _ in range(N)]
        a.sort()
        eq = 0
        invalid = False
        for i, val in enumerate(a, start=1):
            if val > i:
                invalid = True
                break
            if val == i:
                eq += 1
        if invalid or eq % 2 == 0:
            out.append('Second')
        else:
            out.append('First')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

